import { useState } from "react"
import {
  ArrowDownIcon,
  ArrowUpIcon,
  EyeIcon,
  MoreHorizontalIcon,
  PencilIcon,
  XIcon,
  DownloadIcon,
  MailIcon,
  PrinterIcon,
} from "lucide-react"

import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Checkbox } from "@/components/ui/checkbox"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table"

const bookings = [
  {
    id: 1,
    property: "Downtown Studio",
    guest: "Alice Johnson",
    checkIn: "2025-06-10",
    checkOut: "2025-06-17",
    status: "Confirmed",
    amount: "$1,200",
    nights: 7,
  },
  {
    id: 2,
    property: "Beachfront Villa",
    guest: "John Smith",
    checkIn: "2025-07-15",
    checkOut: "2025-07-22",
    status: "Pending",
    amount: "$2,400",
    nights: 7,
  },
  {
    id: 3,
    property: "Mountain View Cabin",
    guest: "Sara Brown",
    checkIn: "2025-05-01",
    checkOut: "2025-05-08",
    status: "Completed",
    amount: "$950",
    nights: 7,
  },
  {
    id: 4,
    property: "City Center Studio",
    guest: "Michael Wilson",
    checkIn: "2025-06-05",
    checkOut: "2025-06-12",
    status: "Cancelled",
    amount: "$780",
    nights: 7,
  },
  {
    id: 5,
    property: "Lakeside Cottage",
    guest: "Emily Davis",
    checkIn: "2025-08-10",
    checkOut: "2025-08-17",
    status: "Confirmed",
    amount: "$1,100",
    nights: 7,
  },
  {
    id: 6,
    property: "Modern Loft",
    guest: "David Martinez",
    checkIn: "2025-06-20",
    checkOut: "2025-06-27",
    status: "Confirmed",
    amount: "$950",
    nights: 7,
  },
  {
    id: 7,
    property: "Seaside Bungalow",
    guest: "Jessica Lee",
    checkIn: "2025-07-05",
    checkOut: "2025-07-12",
    status: "Pending",
    amount: "$1,300",
    nights: 7,
  },
  {
    id: 8,
    property: "Historic Townhouse",
    guest: "Daniel Taylor",
    checkIn: "2025-05-15",
    checkOut: "2025-05-22",
    status: "Completed",
    amount: "$1,450",
    nights: 7,
  },
]

interface BookingsTableProps {
  filters: any
}

export function BookingsTable({ filters }: BookingsTableProps) {
  const [sortColumn, setSortColumn] = useState<string | null>("checkIn")
  const [sortDirection, setSortDirection] = useState<"asc" | "desc">("desc")
  const [selectedRows, setSelectedRows] = useState<number[]>([])

  const handleBulkExport = () => {
    console.log("Exporting selected bookings:", selectedRows)
    // In a real app, you would export the selected bookings
  }

  const handleBulkEmail = () => {
    console.log("Sending emails to selected bookings:", selectedRows)
    // In a real app, you would send emails to selected guests
  }

  const handleSort = (column: string) => {
    if (sortColumn === column) {
      setSortDirection(sortDirection === "asc" ? "desc" : "asc")
    } else {
      setSortColumn(column)
      setSortDirection("asc")
    }
  }

  const toggleSelectAll = () => {
    if (selectedRows.length === bookings.length) {
      setSelectedRows([])
    } else {
      setSelectedRows(bookings.map((booking) => booking.id))
    }
  }

  const toggleSelectRow = (id: number) => {
    if (selectedRows.includes(id)) {
      setSelectedRows(selectedRows.filter((rowId) => rowId !== id))
    } else {
      setSelectedRows([...selectedRows, id])
    }
  }

  const getStatusColor = (status: string) => {
    switch (status) {
      case "Confirmed":
        return "bg-green-100 text-green-800 hover:bg-green-100 border-green-200"
      case "Pending":
        return "bg-yellow-100 text-yellow-800 hover:bg-yellow-100 border-yellow-200"
      case "Completed":
        return "bg-blue-100 text-blue-800 hover:bg-blue-100 border-blue-200"
      case "Cancelled":
        return "bg-red-100 text-red-800 hover:bg-red-100 border-red-200"
      default:
        return "bg-gray-100 text-gray-800 hover:bg-gray-100 border-gray-200"
    }
  }

  // Apply sorting
  const sortedBookings = [...bookings].sort((a, b) => {
    if (!sortColumn) return 0

    const aValue = a[sortColumn as keyof typeof a]
    const bValue = b[sortColumn as keyof typeof b]

    if (aValue < bValue) return sortDirection === "asc" ? -1 : 1
    if (aValue > bValue) return sortDirection === "asc" ? 1 : -1
    return 0
  })

  // In a real app, you would apply filters here
  const filteredBookings = sortedBookings

  return (
    <div className="rounded-md border">
      <Table>
        <TableHeader>
          <TableRow>
            <TableHead className="w-12">
              <Checkbox checked={selectedRows.length === bookings.length} onCheckedChange={toggleSelectAll} />
            </TableHead>
            <TableHead className="cursor-pointer" onClick={() => handleSort("property")}>
              <div className="flex items-center gap-1">
                Property
                {sortColumn === "property" &&
                  (sortDirection === "asc" ? (
                    <ArrowUpIcon className="h-4 w-4" />
                  ) : (
                    <ArrowDownIcon className="h-4 w-4" />
                  ))}
              </div>
            </TableHead>
            <TableHead className="cursor-pointer" onClick={() => handleSort("guest")}>
              <div className="flex items-center gap-1">
                Guest
                {sortColumn === "guest" &&
                  (sortDirection === "asc" ? (
                    <ArrowUpIcon className="h-4 w-4" />
                  ) : (
                    <ArrowDownIcon className="h-4 w-4" />
                  ))}
              </div>
            </TableHead>
            <TableHead className="cursor-pointer" onClick={() => handleSort("checkIn")}>
              <div className="flex items-center gap-1">
                Check-in
                {sortColumn === "checkIn" &&
                  (sortDirection === "asc" ? (
                    <ArrowUpIcon className="h-4 w-4" />
                  ) : (
                    <ArrowDownIcon className="h-4 w-4" />
                  ))}
              </div>
            </TableHead>
            <TableHead className="cursor-pointer" onClick={() => handleSort("checkOut")}>
              <div className="flex items-center gap-1">
                Check-out
                {sortColumn === "checkOut" &&
                  (sortDirection === "asc" ? (
                    <ArrowUpIcon className="h-4 w-4" />
                  ) : (
                    <ArrowDownIcon className="h-4 w-4" />
                  ))}
              </div>
            </TableHead>
            <TableHead>Nights</TableHead>
            <TableHead className="cursor-pointer" onClick={() => handleSort("amount")}>
              <div className="flex items-center gap-1">
                Amount
                {sortColumn === "amount" &&
                  (sortDirection === "asc" ? (
                    <ArrowUpIcon className="h-4 w-4" />
                  ) : (
                    <ArrowDownIcon className="h-4 w-4" />
                  ))}
              </div>
            </TableHead>
            <TableHead className="cursor-pointer" onClick={() => handleSort("status")}>
              <div className="flex items-center gap-1">
                Status
                {sortColumn === "status" &&
                  (sortDirection === "asc" ? (
                    <ArrowUpIcon className="h-4 w-4" />
                  ) : (
                    <ArrowDownIcon className="h-4 w-4" />
                  ))}
              </div>
            </TableHead>
            <TableHead className="w-24">Actions</TableHead>
          </TableRow>
        </TableHeader>
        {selectedRows.length > 0 && (
          <div className="flex items-center gap-2 p-4 bg-blue-50 border-b">
            <span className="text-sm text-blue-700">{selectedRows.length} selected</span>
            <Button variant="outline" size="sm" onClick={handleBulkExport}>
              <DownloadIcon className="h-4 w-4 mr-1" />
              Export
            </Button>
            <Button variant="outline" size="sm" onClick={handleBulkEmail}>
              <MailIcon className="h-4 w-4 mr-1" />
              Email Guests
            </Button>
            <Button variant="outline" size="sm">
              <PrinterIcon className="h-4 w-4 mr-1" />
              Print
            </Button>
          </div>
        )}
        <TableBody>
          {filteredBookings.map((booking) => (
            <TableRow key={booking.id} className={selectedRows.includes(booking.id) ? "bg-muted/50" : ""}>
              <TableCell>
                <Checkbox
                  checked={selectedRows.includes(booking.id)}
                  onCheckedChange={() => toggleSelectRow(booking.id)}
                />
              </TableCell>
              <TableCell className="font-medium">{booking.property}</TableCell>
              <TableCell>{booking.guest}</TableCell>
              <TableCell>
                {new Date(booking.checkIn).toLocaleDateString("en-US", {
                  month: "short",
                  day: "numeric",
                  year: "numeric",
                })}
              </TableCell>
              <TableCell>
                {new Date(booking.checkOut).toLocaleDateString("en-US", {
                  month: "short",
                  day: "numeric",
                  year: "numeric",
                })}
              </TableCell>
              <TableCell>{booking.nights}</TableCell>
              <TableCell className="font-medium">{booking.amount}</TableCell>
              <TableCell>
                <Badge variant="outline" className={getStatusColor(booking.status)}>
                  {booking.status}
                </Badge>
              </TableCell>
              <TableCell>
                <DropdownMenu>
                  <DropdownMenuTrigger asChild>
                    <Button variant="ghost" size="icon" className="h-8 w-8">
                      <MoreHorizontalIcon className="h-4 w-4" />
                      <span className="sr-only">Open menu</span>
                    </Button>
                  </DropdownMenuTrigger>
                  <DropdownMenuContent align="end">
                    <DropdownMenuItem className="flex items-center gap-2">
                      <EyeIcon className="h-4 w-4" />
                      View Details
                    </DropdownMenuItem>
                    {booking.status === "Pending" && (
                      <>
                        <DropdownMenuItem className="flex items-center gap-2">
                          <PencilIcon className="h-4 w-4" />
                          Modify
                        </DropdownMenuItem>
                        <DropdownMenuSeparator />
                        <DropdownMenuItem className="flex items-center gap-2 text-red-600">
                          <XIcon className="h-4 w-4" />
                          Cancel
                        </DropdownMenuItem>
                      </>
                    )}
                  </DropdownMenuContent>
                </DropdownMenu>
              </TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </div>
  )
}
